import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";

interface TS {
  prefix: string;
  group: string;
  sub: string;
  difficulty: D;
  items: Array<[string, string, string, string]>;
}

function gen(sets: TS[]): ScenarioQuestion[] {
  const r: ScenarioQuestion[] = [];
  for (const s of sets) {
    for (let i = 0; i < s.items.length; i++) {
      const [sc, qu, a, f] = s.items[i];
      r.push({ id: `${s.prefix}-${i+1}`, formatType: "scenario", categoryGroup: s.group, subcategory: s.sub, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: s.difficulty });
    }
  }
  return r;
}

const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

const sets: TS[] = [
  { prefix:"sq-et3-ips1", group:ip, sub:"scenario_responses", difficulty:"beginner", items:[
    ["A patient asks you why they need to wear hospital-issued socks.","How would you explain non-slip sock importance?","Non-slip socks have special grip on the bottom that prevents you from sliding on our floors, which are very smooth. Falls in the hospital can cause serious injuries, especially if you are already weakened. These socks are one of our most effective and simplest safety tools.","Simple safety education with rationale."],
    ["A patient asks why they keep getting woken up at night for vital signs.","How would you explain nighttime monitoring?","I understand it is frustrating to be woken up. We check your vital signs overnight because some conditions can change while you sleep. These checks help us catch problems early when they are easier to treat. I will try to combine my nighttime checks to minimize disruptions.","Empathetic explanation of monitoring rationale."],
    ["A patient asks you to turn off the bed alarm because it keeps going off.","How would you respond to a bed alarm complaint?","I understand the alarm is annoying. It is set because you are at risk for falling, and falls in the hospital can cause serious injuries. Instead of turning it off, let me adjust the sensitivity and make sure you have everything you need within reach so it does not activate as often.","Safety maintenance with comfort accommodation."],
    ["A patient asks if they can eat before their surgery tomorrow.","How would you explain NPO status?","Having an empty stomach for surgery is very important for your safety. If there is food in your stomach during anesthesia, it could come up and get into your lungs, which is a serious complication. The timing of when you stop eating depends on your surgery time, so let me check the specific instructions.","Safety-focused NPO education."],
    ["A patient asks why they need to get out of bed after surgery.","How would you explain early ambulation importance?","Getting up and moving after surgery helps prevent blood clots, pneumonia, and muscle weakness. It also helps your bowels start working again and promotes healing. I know it is uncomfortable, but even a short walk makes a big difference in your recovery speed.","Evidence-based ambulation motivation."],
    ["A patient asks why their IV site needs to be changed.","How would you explain IV site rotation?","IV sites need to be changed every 72-96 hours because the longer a needle stays in one place, the higher the risk of infection or vein inflammation. Your vein needs rest to heal. I will find a comfortable new location for the new IV.","IV rotation rationale with comfort focus."],
    ["A patient is upset about receiving a different generic medication.","How would you explain generic medication equivalence?","Generic medications contain the same active ingredient in the same strength as brand-name drugs. The FDA requires them to work the same way in your body. The pills may look different because different manufacturers use different shapes and colors, but the medicine inside is identical.","Generic medication equivalence education."],
    ["A patient asks why they need to wear compression boots.","How would you explain sequential compression device purpose?","These boots gently squeeze your legs in a rhythm that mimics walking. When you are in bed, blood can pool in your legs and form dangerous clots. These devices keep the blood moving to prevent clots from forming. They are especially important after surgery or when you cannot walk.","DVT prevention device education."],
    ["A patient asks why their nurse is scanning their wristband before giving medication.","How would you explain barcode medication verification?","Scanning your wristband and the medication barcode is our way of triple-checking that you are getting the right medication, in the right dose, at the right time. It is like a safety net that catches errors before they reach you. This technology has significantly reduced medication errors.","Technology-based safety education."],
    ["A patient asks why they cannot have visitors after 8 PM.","How would you explain visiting hour restrictions?","Visiting hours are set to balance your need for family support with your need for rest and recovery. Sleep is essential for healing, and nighttime is when your body does its most intensive repair work. We want to make sure you get the rest you need to recover as quickly as possible.","Rest-based visiting hour rationale."],
  ]},
  { prefix:"sq-et3-ips2", group:ip, sub:"scenario_responses", difficulty:"intermediate", items:[
    ["A patient asks you about a medication error they read about in the news.","How would you address patient concerns about medication safety?","I understand your concern. Medication safety is our highest priority. We use multiple checks including barcode scanning, pharmacist verification, and nurse double-checks to prevent errors. While no system is perfect, our processes significantly reduce the risk of errors reaching patients.","Transparent safety system explanation."],
    ["A patient wants to record your conversation about their care.","How would you handle a patient recording clinical conversations?","I would check facility policy first. In most cases I would say: 'If recording helps you remember your care instructions, that is fine. I want to make sure you understand everything. However, please be mindful of not recording other patients or staff members who have not consented.'","Recording policy with patient benefit framing."],
    ["A patient asks if they should get a second opinion.","How would you respond to second opinion inquiries?","Getting a second opinion is your right and often a wise decision, especially for major diagnoses or treatment plans. I would never discourage you from seeking additional perspectives. Would you like help understanding how to arrange a second opinion through your insurance?","Supporting patient empowerment through second opinions."],
    ["A patient asks you to recommend a specific surgeon.","How would you handle surgeon recommendation requests?","I cannot recommend specific physicians, but I can share objective information: which surgeons specialize in your procedure, their volume of similar cases, and patient satisfaction data that is publicly available. I would encourage you to meet with potential surgeons and choose the one you feel most comfortable with.","Objective provider information without personal recommendation."],
    ["A patient asks about alternative medicine for their condition.","How would you discuss alternative medicine?","I respect your interest in exploring all options. Some complementary approaches have evidence supporting their use alongside conventional treatment. I would encourage you to discuss any alternative therapies with your physician, especially to check for interactions with your current medications. Integration is safer than substitution.","Integrative medicine discussion with safety awareness."],
    ["A patient asks if their nurse has ever made a mistake.","How would you answer questions about personal errors?","I believe in transparency. Every healthcare provider, including me, has made mistakes during their career. What matters is how we respond: we report errors immediately, learn from them, and implement systems to prevent them from recurring. Our safety culture encourages honesty because it protects patients.","Honest error culture acknowledgment."],
    ["A patient questions whether their treatment is evidence-based.","How would you address evidence-based treatment questions?","That is an excellent question. Your treatment plan is based on current clinical guidelines and research evidence. I can provide you with patient-friendly resources about the evidence behind your treatment if you would like. Being informed about your care makes you a better partner in your health.","Evidence-based practice transparency."],
    ["A patient asks about their right to refuse a medical student being present.","How would you explain patient rights regarding medical students?","You absolutely have the right to decline having students participate in your care. Your decision will not affect the quality of care you receive in any way. If you are comfortable with students observing but not performing procedures, that is also an option. Your comfort is our priority.","Clear student participation rights."],
    ["A patient asks why different nurses give different answers.","How would you address inconsistent information from staff?","I apologize for the confusion. Let me clarify the correct information for you right now and make sure it is documented clearly so everyone on your care team communicates consistently. If you ever receive conflicting information again, please let us know immediately so we can correct it.","Inconsistency acknowledgment with resolution."],
    ["A patient asks about clinical trials for their condition.","How would you discuss clinical trial options?","Clinical trials can offer access to cutting-edge treatments. I can connect you with our research coordinator who can explain what trials are available for your condition. Participation is always voluntary, and you can withdraw at any time. It is important to understand both potential benefits and risks before deciding.","Clinical trial information with voluntariness emphasis."],
  ]},
  { prefix:"sq-et3-wsd1", group:ws, sub:"delegation", difficulty:"intermediate", items:[
    ["You need to delegate insulin administration to an LPN.","Can an LPN administer insulin?","In most states, LPNs can administer insulin after proper training and competency verification. I would verify the LPN's training status, provide the specific dose and administration instructions, and follow up to confirm administration and patient response. The RN retains accountability for the insulin therapy management.","Scope-verified insulin delegation."],
    ["You need a CNA to collect a stool specimen.","How would you delegate stool specimen collection?","I would instruct: 'Please collect a stool specimen from Mrs. Davis when she has her next bowel movement. Use the clean specimen container from the supply room. Do not contaminate it with urine or toilet water. Label it with her name and date, and bring it to me within 30 minutes of collection. Let me know when it is ready.'","Specific specimen collection delegation."],
    ["You need to delegate blood glucose monitoring to an LPN during a busy period.","How would you delegate blood glucose monitoring?","I would provide specific instructions: 'Please check fasting blood glucose on rooms 301, 303, and 305 before breakfast trays arrive. Use the unit's glucometer and follow the calibration protocol. For any result below 70 or above 300, notify me immediately. Document all results in the MAR with the time of the check.'","Parameter-specific glucose monitoring delegation."],
    ["You need to delegate feeding assistance to a CNA for multiple patients.","How would you ensure safe meal assistance delegation?","I would review each patient's diet restrictions and swallowing precautions: 'Mr. Kim is on thickened liquids and needs supervision while eating. Mrs. Lee is NPO—no food or drink. Mr. Johnson needs assistance cutting his food but can feed himself. Report any coughing, choking, or difficulty swallowing to me immediately.'","Diet-specific feeding delegation with safety alerts."],
    ["You need to delegate wound packing to an LPN.","Can you delegate wound packing to an LPN?","LPN wound care scope varies by state and facility policy. If within scope, I would verify the LPN's competency, provide specific orders for packing material, technique, and frequency, assess the wound myself first, and follow up to evaluate the LPN's work. Complex wounds requiring debridement remain RN or provider responsibility.","Scope-dependent wound care delegation."],
    ["You need to delegate chest tube output measurement to a CNA.","Can a CNA measure chest tube output?","Measuring and recording output is within CNA scope, but assessing the output characteristics is not. I would instruct: 'Please measure and record the drainage volume every hour. Note the color—if it changes from yellow to bright red, or if the volume suddenly increases significantly, notify me immediately. Do not touch or adjust the drainage system.'","Output monitoring delegation with assessment limits."],
    ["You need an LPN to monitor a patient receiving a blood transfusion.","How would you delegate blood transfusion monitoring?","After I initiate the transfusion and complete the first 15-minute assessment, an LPN can monitor vital signs per protocol. I would provide specific parameters: 'Check VS every 15 minutes for the first hour, then every 30 minutes. Report immediately if: temperature rises 1 degree, BP drops 20 systolic, patient develops hives, back pain, or shortness of breath.'","Post-initiation transfusion monitoring delegation."],
    ["You need to delegate turning a patient with a spinal cord injury.","How would you delegate specialized positioning?","I would demonstrate the log-roll technique and supervise the first attempt: 'Mr. Chen must be turned using strict log-roll technique to maintain spinal alignment. Three people minimum. One controls the head, one turns the torso, one turns the legs—all moving simultaneously on a count. Never flex, extend, or rotate the spine.'","Technique-specific positioning delegation with demonstration."],
    ["You need to delegate wound care documentation to an LPN who performed the dressing change.","How would you ensure adequate wound care documentation?","I would specify documentation requirements: 'Please document the wound assessment: size in centimeters, depth, wound bed appearance, drainage amount and color, surrounding skin condition, the dressing applied, and the patient's pain level before and after. If you notice any changes from the last assessment, note them specifically.'","Documentation-standard wound care delegation."],
    ["You need to delegate discharge vital signs to a CNA.","How would you delegate pre-discharge vital signs?","I would instruct: 'Please obtain a full set of vital signs including orthostatic blood pressures for Mr. Park before his discharge. Check lying, sitting, and standing BP with 2 minutes between each position. If his systolic drops more than 20 or he feels dizzy upon standing, let me know immediately.'","Orthostatic-inclusive discharge vital sign delegation."],
  ]},
  { prefix:"sq-et3-wsh1", group:ws, sub:"handoff_communication", difficulty:"beginner", items:[
    ["You are preparing to give report on a patient who had a quiet shift.","How do you report on a patient with no events?","I would still provide essential information: current diagnosis, medication schedule, assessment findings, upcoming needs, and any patient preferences. 'Quiet shift' does not mean 'no report needed.' The receiving nurse needs baseline information to recognize any changes during their shift.","Complete reporting even for uneventful shifts."],
    ["You need to hand off a patient mid-shift for a break.","What information does a break relief nurse need?","I would provide: patient names and diagnoses, any pending or time-critical tasks, current status and concerns, medication due times, and where to find me if needed. I would keep it brief but comprehensive: 'Room 302 has IV antibiotics due at 1400. Room 305 is awaiting discharge orders. Call me if anything changes.'","Concise break relief handoff."],
    ["You are receiving handoff on a patient from a specialty you are unfamiliar with.","How would you receive report on an unfamiliar specialty patient?","I would ask targeted questions about the specific care needs: 'What monitoring is unique to this condition? What complications should I watch for? What parameters should I report immediately? Are there any special medications or equipment I need to know about?' I would not pretend to understand terminology I do not know.","Specialty-unfamiliar handoff questioning."],
    ["Your handoff report is interrupted by a patient emergency.","How would you manage a handoff interruption?","I would briefly notify the receiving nurse about the emergency, provide essential safety information for any remaining patients quickly, respond to the emergency, and complete the full handoff as soon as the emergency is resolved. I would not leave without ensuring the receiving nurse has minimum safe information.","Emergency-interrupted handoff management."],
    ["You discover after handoff that you forgot to mention something important.","How would you handle a handoff omission you discover later?","I would contact the receiving nurse immediately, regardless of the time: 'I forgot to mention that Mr. Johnson's potassium was 5.8 at 1600—the doctor was notified and ordered a recheck at 2000. I apologize for the omission.' I would not wait until the next shift to correct important handoff gaps.","Immediate handoff omission correction."],
    ["You are giving handoff to an agency nurse who does not know your unit.","How would you adjust handoff for an unfamiliar nurse?","I would provide additional context: unit-specific protocols, where supplies and emergency equipment are located, which patients require the most attention, and how to reach the charge nurse. I would offer my phone number for questions during the shift. Extra support for unfamiliar nurses protects patient safety.","Enhanced handoff for unfamiliar staff."],
    ["You need to communicate care plan changes that occurred during a meeting you attended.","How would you relay meeting decisions to the care team?","I would document the key decisions in the patient's chart, update the care plan, communicate verbally during the next handoff, and ensure all team members are aware of changes. I would use a standardized format: 'At today's team meeting, the plan changed to [specific changes]. The rationale is [reason].'","Meeting decision dissemination."],
    ["A patient's family asks you to relay information to the night shift.","How would you include family communication in handoff?","I would include it in my report: 'The patient's daughter called at 1600 and requested a call back about the discharge plan. Her number is in the chart. The patient wants their wife present for all care discussions.' Family communication needs are part of comprehensive handoff.","Family communication integration in handoff."],
    ["You are giving handoff on a patient with a pending critical test result.","How would you communicate pending results during handoff?","I would be specific: 'Mrs. Garcia's CT scan was completed at 1700 but results are not back yet. The physician ordered it to rule out PE. If the result comes back positive, the physician wants to be called immediately and the heparin protocol should be initiated. Here is the physician's contact number.'","Pending result handoff with contingency plan."],
    ["You need to give a phone handoff because you cannot stay for in-person report.","How would you give an effective phone handoff?","I would be extra organized since nonverbal cues are absent: use a standardized format, spell out medication names, repeat critical values, ask the receiving nurse to read back key points, and ensure they have my contact number for questions. Phone handoffs require more explicit communication than face-to-face.","Phone-specific handoff adaptations."],
  ]},
  { prefix:"sq-et3-wsdc1", group:ws, sub:"difficult_coworkers", difficulty:"intermediate", items:[
    ["A colleague refuses to help you with a two-person task.","How would you handle a colleague refusing to help?","I would ask if there is a reason they cannot help right now—they may have their own urgent tasks. If they are simply unwilling, I would find another colleague and address the pattern later if it is recurring. Patient safety should not depend on any single colleague's cooperation.","Pragmatic alternative-seeking with pattern monitoring."],
    ["A charge nurse assigns you the most difficult patients every shift.","How would you address consistently difficult assignments?","I would discuss it constructively: 'I have noticed I have been assigned the highest-acuity patients for several consecutive shifts. While I appreciate the confidence, I want to make sure I am providing safe care without burnout. Can we discuss rotating the assignment distribution?' I would document the pattern if needed.","Data-based assignment equity discussion."],
    ["A colleague spreads rumors about your clinical competence.","How would you address competence-related rumors?","I would address the source directly: 'I have heard that concerns about my clinical skills are being discussed among staff. If you have specific concerns, I would appreciate you sharing them with me directly so I can address them. I am committed to safe patient care and continuous improvement.' I would involve the manager if the rumors continued.","Direct rumor confrontation with improvement openness."],
    ["A colleague undermines your authority with patients.","How would you handle authority undermining?","I would address it privately: 'When you tell my patient that my assessment was wrong, it undermines their trust in my care and creates confusion. If you disagree with my clinical judgment, please discuss it with me directly. We can review the situation together and ensure the patient receives the best care.'","Private authority undermining discussion."],
    ["A colleague frequently calls in sick, increasing your workload.","How would you manage increased workload from colleague absences?","I would not confront the colleague about their attendance—that is a management issue. I would communicate my workload concern to the charge nurse: 'With the staffing gap today, I need help prioritizing my patients' needs to ensure safety.' I would document any situations where patient care is compromised due to staffing.","Workload communication without colleague confrontation."],
    ["A colleague constantly asks you to cover their tasks.","How would you handle a colleague who relies on you excessively?","I would set boundaries: 'I am happy to help in urgent situations, but I have noticed I am covering your tasks regularly, which affects my ability to care for my own patients. I need to focus on my assignment. If you are consistently overwhelmed, would you consider discussing workload with the charge nurse?'","Boundary-setting with alternative suggestion."],
    ["A colleague makes insensitive comments about patients.","How would you address insensitive patient remarks?","I would address it immediately: 'I am uncomfortable with that comment. Our patients deserve respect regardless of their circumstances. Making those remarks can also be overheard and damages our unit's professionalism.' If the behavior continued, I would report it as a professional conduct concern.","Immediate insensitivity correction."],
    ["A colleague takes credit for your patient care improvement.","How would you address stolen recognition?","I would make my contributions visible through documentation and email follow-ups. During meetings, I would clearly state my involvement: 'The project we implemented included my analysis of the fall data and the protocol I developed.' I would address it privately if needed. Recognition should be attributed accurately.","Contribution visibility with private correction."],
  ]},
  { prefix:"sq-et3-wsic1", group:ws, sub:"interdisciplinary_communication", difficulty:"intermediate", items:[
    ["A pharmacist questions your medication administration timing.","How would you respond to a pharmacist's timing concern?","I would explain my clinical rationale: 'I administered the antibiotic at 0800 instead of 0900 because the patient was going for a procedure at 0830 and would miss the dose. I notified the physician about the timing change.' If the pharmacist has a valid concern about timing, I would acknowledge it and adjust future administration.","Clinical rationale for administration timing."],
    ["A social worker disagrees with your assessment of a patient's home safety.","How would you navigate a home safety disagreement?","I would present my nursing observations: 'My assessment is based on the patient's functional limitations I have observed during care: inability to stand independently, medication management confusion, and fall risk. Can we discuss these findings together and determine the safest discharge plan?'","Observation-based safety assessment sharing."],
    ["An occupational therapist recommends a different approach to patient mobility.","How would you integrate OT recommendations?","I would learn from the OT's expertise: 'Can you show me the technique you recommend? I want to make sure I am reinforcing the same approach during nursing care.' Consistent interdisciplinary approaches improve patient outcomes. I would modify my care plan to align with the OT's recommendations.","Learning from OT expertise for consistency."],
    ["A respiratory therapist and nurse disagree about oxygen titration.","How would you resolve an oxygen management disagreement?","I would review the physician's orders and protocol together: 'Let us look at the current oxygen order and the patient's trending SpO2. The order says titrate to maintain 92-96%. Based on the current data, what do you recommend?' Resolving disagreements through objective data and orders prevents conflict.","Order-based oxygen management resolution."],
    ["A physician dismisses your nursing assessment.","How would you persist when a physician dismisses your concern?","I would use assertive communication: 'I understand you may not share my concern, but I have documented specific findings that I believe warrant attention. If we do not address them and the patient deteriorates, I will need to escalate through the chain of command. I want us to work together on this.'","Assertive escalation with documentation."],
    ["A wound care nurse recommends a different dressing than what is ordered.","How would you manage a wound care recommendation conflict?","I would recognize the wound care nurse as the expert: 'I value your recommendation. The current order specifies wet-to-dry dressings, but you are recommending a foam dressing. Can you contact the physician to discuss changing the order based on your assessment?' Expert recommendations should inform order changes through proper channels.","Expert recommendation facilitation."],
    ["A case manager is pressuring early discharge.","How would you handle discharge pressure from case management?","I would present clinical data: 'I understand the length-of-stay concern. However, the patient's clinical status does not yet meet our discharge criteria: blood pressure remains labile, pain is not controlled on the oral regimen, and they cannot demonstrate independent medication management. Premature discharge risks readmission.'","Clinical criteria-based discharge pushback."],
    ["A chaplain reports spiritual distress that may affect medical compliance.","How would you integrate chaplain observations into care?","I would incorporate the chaplain's findings into the care plan: 'Thank you for that insight. If the patient's spiritual distress is affecting their willingness to accept treatment, we should address it as part of our care approach. Can you continue working with them while I adjust our nursing care plan to support their spiritual needs?'","Spiritual care integration into clinical planning."],
  ]},
  { prefix:"sq-et3-ctd1", group:ct, sub:"documentation_challenges", difficulty:"beginner", items:[
    ["You need to document a telephone order from a physician.","How do you properly document a telephone order?","I would document: 'Telephone order received from Dr. [Name] at [time] for [specific order].' I would read the order back for verification and note 'read-back verified.' I would sign the order with my name, credentials, date, and time. The physician should authenticate the order within the facility's required timeframe.","Telephone order documentation protocol."],
    ["You need to document a patient's pain assessment.","What elements are required in pain documentation?","I would document: pain location, intensity (numeric or descriptive scale), quality, onset and duration, aggravating and alleviating factors, intervention provided, and re-assessment results. For example: 'Reports 7/10 sharp pain in right lower abdomen, constant since 0600. Morphine 2mg IV given per order. Re-assessment at 0930: pain 4/10.'","Complete pain assessment documentation."],
    ["You need to document a fall that occurred when no one was present.","How would you document an unwitnessed fall?","I would document: 'Patient found on floor at [time] in [location]. Patient states [their account of what happened]. Assessment findings: [injuries, mental status, vital signs]. Provider notified at [time]. Orders received: [specific orders]. Incident report completed.' I would not speculate about what happened—document only what is known.","Factual unwitnessed fall documentation."],
    ["You need to document wound measurements.","How would you accurately document wound dimensions?","I would document: location using anatomical landmarks, length (head to toe direction), width (side to side), depth (using sterile applicator), tunneling (using clock-face directions), wound bed description (percentage of granulation, slough, necrotic tissue), drainage characteristics, and surrounding skin condition. I would include measurements in centimeters.","Precise wound measurement documentation."],
    ["You need to document patient education provided.","What should education documentation include?","I would document: topic taught, method used (verbal, demonstration, written materials, video), patient's response and engagement level, barriers to learning identified, teach-back results, and plan for follow-up education. Example: 'Instructed on insulin self-injection technique via demonstration. Patient performed return demonstration accurately. Verbalized understanding of hypoglycemia signs.'","Comprehensive education documentation with outcomes."],
    ["You need to document a patient's advance directive discussion.","How would you document advance directive conversations?","I would document: 'Discussed advance directives with patient. Patient states they have/do not have existing advance directive. Code status verified as [full code/DNR/DNAR]. Healthcare proxy identified as [name, relationship, contact]. Patient's specific wishes regarding [resuscitation, intubation, feeding tubes] documented in care plan. Copy placed in chart.'","Advance directive documentation elements."],
    ["You need to add a late entry to your documentation.","How would you properly document a late entry?","I would clearly label it as a late entry: 'Late entry for [date, time of occurrence]. [Clinical information being documented].' I would sign with my name, credentials, and the current date and time. I would not alter previous entries. Late entries should include the reason for the delay if relevant.","Proper late entry format."],
    ["You need to document the application of physical restraints.","What must restraint documentation include?","I would document: physician order with clinical justification, type of restraint applied, time applied, assessment of circulation and skin integrity every 2 hours, release every 2 hours for ROM exercises, toileting and nutrition offered, patient's response, continued clinical need assessment, and alternative interventions attempted before restraint application.","Comprehensive restraint documentation requirements."],
    ["You need to correct an error in your documentation.","How would you correct a charting error?","For paper charts: single line through the error, write 'error' or 'mistaken entry,' initial, and date. For electronic records: follow the system's amendment process, never delete entries. The original entry must remain visible. I would add the correct information as a new entry. Documentation should never be altered to conceal errors.","Documentation correction protocol."],
    ["You need to document a patient's capacity assessment.","How would you document decision-making capacity?","I would document: 'Patient demonstrates/does not demonstrate decision-making capacity as evidenced by: ability to understand information presented about [specific topic], appreciation of how it applies to their situation, ability to reason about risks and benefits, and ability to communicate a clear choice. Capacity assessment specific to [decision being made].'","Decision-specific capacity documentation."],
  ]},
  { prefix:"sq-et3-ctcr1", group:ct, sub:"critical_thinking_drills", difficulty:"beginner", items:[
    ["A patient's white blood cell count is 15,000.","What does a mildly elevated WBC indicate?","WBC of 15,000 (normal 4,500-11,000) indicates leukocytosis, suggesting infection, inflammation, stress response, or medication effect (steroids). I would assess for infection signs, correlate with other findings, and monitor the trend. A mild elevation post-surgery or during acute illness is expected but should still be monitored.","Mild leukocytosis interpretation with clinical correlation."],
    ["A patient's heart rate is 110 at rest.","What causes resting tachycardia?","Resting heart rate of 110 has many causes: pain, anxiety, fever, dehydration, anemia, thyroid dysfunction, medication effects, heart failure, or pulmonary embolism. I would assess for associated symptoms, check temperature, review medications, ensure adequate hydration, and investigate the underlying cause rather than just treating the number.","Tachycardia differential assessment."],
    ["A patient's blood pressure is 88/56.","How would you assess and respond to hypotension?","I would assess for symptoms: dizziness, confusion, cool extremities, decreased urine output. I would check for causes: hypovolemia, medication effects, sepsis, cardiac issues. I would position the patient flat, establish IV access if not present, prepare for fluid resuscitation, and notify the provider with my assessment findings.","Hypotension systematic assessment and response."],
    ["A patient's respiratory rate is 28.","What does tachypnea indicate?","Respiratory rate of 28 (normal 12-20) indicates increased respiratory demand from multiple possible causes: hypoxia, pain, anxiety, fever, metabolic acidosis, pneumonia, PE, or heart failure. I would assess oxygen saturation, lung sounds, work of breathing, and associated symptoms. Tachypnea is often an early warning sign of clinical deterioration.","Tachypnea as early deterioration warning."],
    ["A patient's urine output is 200 mL in 8 hours.","Is this urine output adequate?","For a typical adult, adequate urine output is 0.5 mL/kg/hour. For a 70 kg patient, the minimum is 35 mL/hour or 280 mL in 8 hours. Output of 200 mL in 8 hours (25 mL/hour) is below the threshold and suggests oliguria. I would assess hydration status, fluid intake, renal function, and notify the provider.","Urine output adequacy calculation."],
    ["A patient's temperature is 96.5°F.","What does hypothermia indicate?","Temperature of 96.5°F (35.8°C) is mildly hypothermic. Causes include sepsis (paradoxically), environmental exposure, hypothyroidism, medication effects, or aging-related thermoregulation issues. I would provide warming measures, check for sepsis signs, review medications, and monitor closely. Hypothermia in hospitalized patients can be a sepsis warning sign.","Hypothermia assessment including sepsis consideration."],
    ["A patient's hemoglobin is 8.5 g/dL.","How would you assess and manage mild anemia?","Hemoglobin of 8.5 (normal 12-16 for women, 13.5-17.5 for men) indicates moderate anemia. I would assess for symptoms: fatigue, dizziness, pallor, tachycardia. I would review the cause: blood loss, chronic disease, nutritional deficiency. I would implement fall precautions and anticipate possible transfusion if the patient is symptomatic or the level continues to drop.","Moderate anemia management with fall risk awareness."],
    ["A patient's blood glucose is 250 mg/dL.","How would you manage moderately elevated blood glucose?","Blood glucose of 250 is significantly elevated. I would administer sliding scale insulin as ordered, ensure adequate hydration, monitor for DKA symptoms if type 1 diabetic, investigate contributing factors (missed medication, dietary indiscretion, stress, infection), and recheck glucose in 2-4 hours. I would notify the provider if glucose remains elevated despite intervention.","Moderate hyperglycemia management."],
    ["A patient's oxygen saturation drops to 89%.","How would you respond to mild desaturation?","SpO2 of 89% is below normal (>95%) and requires intervention. I would assess the patient's respiratory status, apply or increase supplemental oxygen, ensure proper pulse oximeter placement, position upright, assess breath sounds, and notify the provider. For COPD patients, I would check their baseline target saturation before aggressive oxygen therapy.","Desaturation response with patient-specific targets."],
    ["A patient's INR is 1.8.","Is this INR therapeutic?","An INR of 1.8 is subtherapeutic for most indications requiring anticoagulation (target 2.0-3.0 for most conditions, 2.5-3.5 for mechanical heart valves). The patient may be at increased clot risk. I would notify the provider for possible dose adjustment, check dietary vitamin K intake, and assess for medication interactions that might affect warfarin levels.","INR interpretation with therapeutic targets."],
  ]},
  { prefix:"sq-et3-pdec1", group:pd, sub:"ethical_dilemmas", difficulty:"intermediate", items:[
    ["A colleague is overheard making disparaging remarks about a patient's weight.","How would you address weight stigma from a colleague?","I would address it directly: 'Comments about patients' weight are stigmatizing and can affect care quality. Research shows weight bias leads to delayed diagnosis and avoidance of healthcare. Let us focus on the patient's clinical needs rather than their body size.' Weight stigma is a healthcare equity issue.","Weight stigma confrontation with evidence."],
    ["A patient's family disagrees with the patient's expressed wishes.","How would you protect patient autonomy against family opposition?","I would center the conversation on the patient's expressed wishes: 'I understand your family's perspective, but your father has clearly expressed his preferences, and he has the capacity to make his own decisions. Our role is to support his choices while ensuring he is fully informed. Would a family meeting with the physician help address everyone's concerns?'","Capacity-based patient autonomy protection."],
    ["You discover a systemic issue that puts multiple patients at risk.","How would you report a systemic safety concern?","I would report through multiple channels: immediate supervisor, incident reporting system, and patient safety officer. I would document the concern with specific examples and the potential patient impact. Systemic issues require system-level responses, not just individual workarounds. I would follow up to ensure the concern is addressed.","Multi-channel systemic safety reporting."],
    ["A patient's insurance denies a medically necessary treatment.","How would you advocate against an insurance denial?","I would work with the care team to: document the medical necessity thoroughly, support the physician's appeal letter with nursing observations, involve case management for peer-to-peer review, connect the patient with patient advocacy organizations, and ensure the patient understands the appeal process and their rights.","Insurance denial advocacy strategies."],
    ["You are asked to prioritize patients based on their insurance status.","How would you handle insurance-based prioritization?","I would refuse: 'Patient care prioritization should be based solely on clinical acuity and need, never on insurance status. This request violates our professional ethics and potentially EMTALA regulations. I will continue to prioritize patients based on clinical assessment.' I would report the request to my supervisor and ethics committee.","Insurance-based prioritization refusal with regulatory awareness."],
    ["A patient asks you not to chart something they told you.","How would you handle a request to omit information from the chart?","I would explain: 'I understand your concern about privacy, but I have a professional obligation to document clinically relevant information. Your medical record is protected by HIPAA and can only be accessed by your care team. If I omit this information, it could affect the safety and quality of your care.'","Documentation obligation explanation with privacy assurance."],
    ["You believe a patient is being coerced into a medical decision.","How would you identify and address medical decision coercion?","I would create a private opportunity to speak with the patient alone: 'I want to make sure you understand your options and that you are making this decision freely. Is there anything you would like to discuss without anyone else present?' If coercion is confirmed, I would involve social work and document my findings.","Coercion assessment with private patient conversation."],
    ["A patient wants to leave AMA during a life-threatening condition.","How would you manage a life-threatening AMA request?","I would ensure the patient has capacity, explain the specific risks of leaving including the possibility of death, document the conversation thoroughly, have them sign the AMA form, provide instructions for emergency return, ensure they have prescriptions for essential medications, and schedule follow-up care. I would not physically prevent them from leaving.","AMA management for critical conditions."],
  ]},
  { prefix:"sq-et3-pdwb1", group:pd, sub:"workplace_bullying", difficulty:"intermediate", items:[
    ["A preceptor is overly harsh in their criticism of new nurses.","How would you address destructive precepting?","I would address it with the preceptor: 'I value constructive feedback, but the way it is being delivered is demoralizing and makes me afraid to ask questions, which could affect patient safety. Can we discuss a more supportive communication approach?' If no improvement, I would request a preceptor change through my manager.","Constructive precepting feedback request."],
    ["A group of nurses are cliquish and exclude others from important information.","How would you handle information gatekeeping?","I would address the impact on patient care: 'I have noticed I am not receiving important updates about patient care changes and unit protocols. This information gap could affect patient safety. Can we implement a communication system that ensures all nurses receive essential updates?' I would propose solutions, not just complaints.","Information access advocacy with solutions."],
    ["A colleague makes passive-aggressive comments during handoff.","How would you address passive-aggression during clinical communication?","I would name the behavior: 'I am sensing some tension in our communication. If there is a concern about my care or documentation, I would appreciate direct feedback so I can address it. Patient safety depends on clear, honest communication between us.'","Direct naming of passive-aggressive communication."],
    ["A nurse consistently gives you the most undesirable tasks during collaborative care.","How would you address unfair task distribution?","I would discuss it directly: 'I have noticed a pattern where I consistently receive the most difficult tasks during our collaborative care. I want to contribute fairly, but the current distribution feels inequitable. Can we discuss rotating these tasks more evenly?' Documentation of the pattern strengthens the conversation.","Pattern-based task equity discussion."],
    ["You witness a nurse being hazed as part of a unit initiation.","How would you intervene against workplace hazing?","I would intervene immediately: 'This is not appropriate and does not represent our professional standards.' I would report the behavior to the unit manager and document what I witnessed. Hazing is a form of workplace bullying that can cause psychological harm and is never acceptable in a professional healthcare setting.","Immediate hazing intervention and reporting."],
  ]},
  { prefix:"sq-et3-cnpe1", group:cn, sub:"performance_evaluation", difficulty:"beginner", items:[
    ["You want to document your achievements for evaluation.","How would you track professional accomplishments?","I would maintain a running accomplishment log including: patient outcomes I contributed to, skills mastered, positive feedback received, committee participation, CE completed, certifications earned, and quality improvement contributions. Having specific examples with dates and outcomes makes evaluations much more productive and convincing.","Ongoing accomplishment tracking system."],
    ["Your evaluation includes a peer review component.","How would you approach peer review?","I would provide honest, constructive feedback focusing on observable behaviors and their impact on patient care. I would include both strengths and areas for growth. I would be specific: 'Sarah consistently demonstrates excellent patient education skills. An area for growth might be delegating more effectively during busy shifts.'","Constructive peer review approach."],
    ["You want to discuss salary increase during your evaluation.","How would you approach a salary discussion?","I would present evidence of my value: 'I have achieved all performance goals, earned my ACLS certification, precepted two new graduates, and contributed to the falls prevention committee which reduced our unit's fall rate by 15%. Based on these contributions and current market rates, I would like to discuss a salary adjustment.'","Value-based salary discussion with evidence."],
    ["Your manager asks you to set goals for the next review period.","How would you set meaningful evaluation goals?","I would use the SMART framework: 'By March, I will complete CCRN certification (Specific, Measurable). I will participate in two quality improvement projects (Achievable). These goals support our unit's need for certified nurses (Relevant). The timeline aligns with my development pace (Time-bound).'","SMART goal-setting for evaluations."],
    ["You disagree with feedback in your evaluation.","How would you handle evaluation disagreement?","I would listen fully before responding, ask for specific examples, present my perspective with evidence, and document my response if the evaluation allows. I would not become defensive: 'I appreciate this feedback. I see the situation differently based on [specific evidence]. Can we discuss how to move forward with a mutual understanding?'","Evidence-based evaluation disagreement."],
  ]},
  { prefix:"sq-et3-cnjo1", group:cn, sub:"job_offer_negotiation", difficulty:"beginner", items:[
    ["You are asked about your salary expectations in a screening call.","How would you handle early salary questions?","I would redirect: 'I am interested in learning more about the full position and compensation package before discussing specific numbers. Can you share the budgeted range for this position? I want to make sure we are aligned before we invest time in the interview process.'","Range-seeking salary deflection."],
    ["An interviewer asks about your biggest accomplishment.","How would you present your biggest achievement?","I would choose an accomplishment that demonstrates nursing-relevant skills: 'My biggest accomplishment was identifying a pattern of medication errors during my clinical rotation and developing a verification checklist that was adopted by the unit. It reduced errors by 30% in three months and demonstrated my commitment to patient safety and quality improvement.'","Achievement with measurable patient impact."],
    ["You are asked why you left or are leaving your current position.","How would you discuss leaving a previous job?","I would be positive and forward-looking: 'I am grateful for the experience I gained. I am looking for a position that offers more opportunities for [specific growth area]. Your unit's reputation for [specific quality] is exactly what I am looking for in my next professional step.' I would never speak negatively about previous employers.","Positive departure framing."],
    ["You receive a verbal offer and want to see it in writing.","How would you request a written offer?","I would say: 'Thank you for the offer—I am very excited about this opportunity. Before I make my final decision, could I receive the complete offer in writing, including salary, benefits, orientation details, and start date? Having everything documented helps me make an informed decision.'","Written offer request with gratitude."],
    ["You want to negotiate your start date.","How would you negotiate your start date?","I would be transparent: 'I want to provide adequate notice to my current employer and take a brief transition period. Could we discuss starting on [specific date] instead? I want to begin this position refreshed and fully committed. I am happy to complete any pre-employment requirements before my start date.'","Professional start date negotiation."],
  ]},
];

